Code Good:
import { gt, asc, eq, desc } from 'drizzle-orm';
import { db } from './db';
import { posts } from './schema';

// Offset-based pagination (simple, ok for small datasets)
async function getPostsOffset(page: number, pageSize: number = 20) {
  const results = await db
    .select()
    .from(posts)
    .orderBy(asc(posts.id))
    .limit(pageSize)
    .offset((page - 1) * pageSize);
  return results;
}

// Cursor-based pagination (efficient for large datasets)
async function getPostsCursor(cursor: number | null, pageSize: number = 20) {
  const query = db
    .select()
    .from(posts)
    .orderBy(asc(posts.id))
    .limit(pageSize + 1); // fetch one extra to check hasMore

  const results = cursor
    ? await query.where(gt(posts.id, cursor))
    : await query;

  const hasMore = results.length > pageSize;
  const data = hasMore ? results.slice(0, -1) : results;
  const nextCursor = hasMore ? data[data.length - 1].id : null;

  return { data, nextCursor, hasMore };
}

