import { db } from './db';
import { products } from './schema';
import type { InferInsertModel } from 'drizzle-orm';

type NewProduct = InferInsertModel<typeof products>;

// Batch insert with chunking for large datasets
async function batchInsertProducts(items: NewProduct[]) {
  const CHUNK_SIZE = 1000;
  const results = [];

  for (let i = 0; i < items.length; i += CHUNK_SIZE) {
    const chunk = items.slice(i, i + CHUNK_SIZE);
    const inserted = await db
      .insert(products)
      .values(chunk)
      .returning();
    results.push(...inserted);
  }

  return results;
}

// Simple batch insert
const newProducts: NewProduct[] = [
  { name: 'Widget A', price: 9.99, sku: 'WA-001' },
  { name: 'Widget B', price: 19.99, sku: 'WB-001' },
  { name: 'Widget C', price: 29.99, sku: 'WC-001' },
];

