import { eq, sql } from 'drizzle-orm';
import { db } from './db';
import { products } from './schema';

// Upsert: insert or update on conflict
async function upsertProduct(sku: string, name: string, price: number) {
  const [result] = await db
    .insert(products)
    .values({ sku, name, price, updatedAt: new Date() })
    .onConflictDoUpdate({
      target: products.sku,
      set: {
        name,
        price,
        updatedAt: new Date(),
      },
    })
    .returning();

  return result;
}

// Batch upsert
async function syncProducts(items: { sku: string; name: string; price: number }[]) {
  return db
    .insert(products)
    .values(items.map((i) => ({ ...i, updatedAt: new Date() })))
    .onConflictDoUpdate({
      target: products.sku,
      set: {
        name: sql`excluded.name`,
        price: sql`excluded.price`,
        updatedAt: new Date(),
      },
    })
    .returning();
}

