import { sql, eq } from 'drizzle-orm';
import { db } from './db';
import { users, orders } from './schema';

// Good: query builder for standard operations
const user = await db.select().from(users).where(eq(users.id, 1));

// Good: raw SQL for performance-critical complex queries
const dashboardStats = await db.execute<{
  totalUsers: number;
  activeUsers: number;
  revenue: number;
}>(sql`
  SELECT
    (SELECT count(*) FROM users) as "totalUsers",
    (SELECT count(*) FROM users WHERE last_active > now() - interval '30 days') as "activeUsers",
    (SELECT coalesce(sum(amount), 0) FROM orders WHERE created_at > now() - interval '30 days') as "revenue"
`);

// Good: analyze slow queries
const explainResult = await db.execute(sql`
  EXPLAIN ANALYZE
  SELECT u.*, count(o.id) as order_count
  FROM users u
  LEFT JOIN orders o ON u.id = o.user_id
  GROUP BY u.id
  ORDER BY order_count DESC
  LIMIT 100
`);
console.log('Query plan:', explainResult);

